#include <stdio.h>

int main() {
    int n, i;
    double sum = 0.0;

    printf("Enter n: ");
    scanf("%d", &n);

    for (i = 1; i <= n; i++) {
        if (i % 2 == 1) { // 奇數項
            sum += (2 * i + 1);
        } else { // 偶數項
            sum -= i;
        }
    }

    printf("The sum of the series is: %.6f\n", sum);

    return 0;
}
```

